import { ref } from 'vue'
import { supabase } from '@/lib/supabase'

export interface CheckoutResult {
  success: boolean
  bill_id: string
  invoice_id: string
  invoice_number: string
  grand_total: number
  linked_crm_surveys?: number
  subtotal?: number
  discount_total?: number
  voucher_discount?: number
  points_discount?: number
  service_charge_amount?: number
  vat_amount?: number
}

export interface CheckoutTotals {
  subtotal: number
  tier_discount: number
  voucher_discount: number
  points_discount: number
  total_discount: number
  net_before_tax: number
  service_charge_percent: number
  service_charge_amount: number
  vat_rate: number
  vat_amount: number
  grand_total: number
}

export interface CheckoutPreview {
  ok: boolean
  order?: Record<string, unknown>
  table?: Record<string, unknown>
  items?: Array<Record<string, unknown>>
  totals: CheckoutTotals
  voucher_valid: boolean
  error?: string
}

export function useCheckout() {
  const checkoutResult = ref<CheckoutResult | null>(null)
  const loading = ref(false)
  const error = ref<string | null>(null)

  /**
   * Preview the EXACT totals process_checkout will compute. Frontend display
   * matches the eventual bill byte-for-byte — no more 10% UI vs 8% DB drift.
   */
  async function previewCheckout(params: {
    branchId: string
    tableId: string
    orderId?: string
    voucherCode?: string
    pointsToRedeem?: number
    customerId?: string
  }): Promise<CheckoutPreview> {
    loading.value = true
    error.value = null
    try {
      const { data, error: err } = await supabase.rpc('hall_get_checkout_totals', {
        p_branch_id: params.branchId,
        p_table_id: params.tableId,
        p_order_id: params.orderId ?? null,
        p_voucher_code: params.voucherCode ?? null,
        p_points_to_use: params.pointsToRedeem ?? 0,
        p_customer_id: params.customerId ?? null,
      })
      if (err) throw err
      const row = (data ?? {}) as { ok?: boolean; error?: string } & Record<string, unknown>
      return {
        ok: row.ok === true,
        order: row.order as Record<string, unknown> | undefined,
        table: row.table as Record<string, unknown> | undefined,
        items: row.items as Array<Record<string, unknown>> | undefined,
        totals: row.totals as CheckoutTotals,
        voucher_valid: row.voucher_valid === true,
        error: row.error,
      }
    } catch (e: any) {
      error.value = e.message || String(e)
      throw e
    } finally {
      loading.value = false
    }
  }

  /**
   * Single-table summary for floor-plan / table-modal previews.
   * Caches by tableId to avoid re-querying when switching back.
   *
   * IMPORTANT: previously the cache never re-fetched after the first load,
   * which meant opening the same table-modal twice in a row would show
   * stale totals — and if the cashier rapidly opened A then B, the B total
   * would appear to "leak" with the previous A value because both views
   * shared the same Map. We now always force a re-fetch by default and
   * only honour the cache when the caller passes `useCache: true`.
   */
  const _tableCache = new Map<string, CheckoutPreview>()
  async function previewTableSummary(
    branchId: string,
    tableId: string,
    options: { useCache?: boolean } = {},
  ): Promise<CheckoutPreview> {
    if (options.useCache) {
      const cached = _tableCache.get(tableId)
      if (cached) return cached
    }
    const fresh = await previewCheckout({ branchId, tableId })
    _tableCache.set(tableId, fresh)
    return fresh
  }
  /**
   * Drop the cached preview for a table. Pass a tableId to drop just that
   * entry (used by realtime order/table events) or omit to drop everything
   * (used after a successful checkout).
   */
  function clearTableCache(tableId?: string) {
    if (tableId) _tableCache.delete(tableId)
    else _tableCache.clear()
  }

  async function executeCheckout(params: {
    orderId: string
    paymentMethod: string
    paymentRef?: string
    voucherCode?: string
    pointsToRedeem?: number
    serviceChargePct?: number
    vatPct?: number
    branchId: string
    cashierId: string
  }): Promise<CheckoutResult> {
    loading.value = true
    error.value = null
    try {
      const { data, error: err } = await supabase.rpc('process_checkout', {
        p_order_id: params.orderId,
        p_branch_id: params.branchId,
        p_cashier_id: params.cashierId,
        p_payment_method: params.paymentMethod,
        p_voucher_code: params.voucherCode || null,
        p_points_to_use: params.pointsToRedeem || 0,
      })
      if (err) throw err
      checkoutResult.value = data as CheckoutResult
      // After successful checkout, drop the cached preview for this table
      // (the table's bill is now Paid — preview is stale).
      _tableCache.clear()
      return data as CheckoutResult
    } catch (e: any) {
      error.value = e.message || String(e)
      throw e
    } finally {
      loading.value = false
    }
  }

  async function checkout(params: any): Promise<CheckoutResult | null> {
    if (!params?.branchId || !params?.cashierId || !params?.paymentMethod) {
      throw new Error('checkout requires branchId, cashierId and paymentMethod')
    }
    return executeCheckout({
      orderId: params.orderId,
      branchId: params.branchId,
      cashierId: params.cashierId,
      paymentMethod: params.paymentMethod,
      voucherCode: params.voucherCode,
      pointsToRedeem: params.pointsToRedeem,
      paymentRef: params.paymentRef,
      serviceChargePct: params.serviceChargePct,
      vatPct: params.vatPct,
    })
  }

  function printReceipt(result: CheckoutResult): void {
    console.log('Printing receipt for', result.invoice_number)
    window.print()
  }

  return {
    checkoutResult,
    loading,
    error,
    previewCheckout,
    previewTableSummary,
    clearTableCache,
    executeCheckout,
    checkout,
    printReceipt,
  }
}

import { onUnmounted, ref } from 'vue'
import type { RealtimeChannel } from '@supabase/supabase-js'
import { supabase } from '@/lib/supabase'
import { useAuth } from './useAuth'

export type RealtimeEvent = 'INSERT' | 'UPDATE' | 'DELETE' | '*'
export type RealtimeStatus = 'connecting' | 'connected' | 'disconnected' | 'error'

interface ChangePayload<T> {
  eventType: RealtimeEvent | string
  new: T
  old: T
}

type Listener<T> = (payload: ChangePayload<T>) => void

/**
 * Module-level dedup state. Each entry holds:
 *   - ch: the shared RealtimeChannel
 *   - listeners: every subscriber's onChange callback (one per `watchTable`
 *     call). The channel broadcasts every event to all listeners.
 *   - ref: total subscriber count; the channel is torn down only when the
 *     last subscriber unmounts.
 *   - status: the latest channel status from the first subscriber's
 *     `subscribe()` callback so late joiners can adopt it.
 *
 * Why a single Map (instead of separate `channels` and `channelRefs` Maps):
 * the previous design had a silent-bug where a SECOND subscriber to the
 * same `(table, event, filter)` tuple never had its callback wired up —
 * the channel was reused as-is and the new `onChange` was discarded
 * because the `if (!ch)` guard skipped the `.on(...)` call entirely.
 * Now every callback lives in a Set the channel can fan out to.
 */
interface ChannelEntry<T = unknown> {
  ch: RealtimeChannel
  listeners: Set<Listener<T>>
  ref: number
  status: RealtimeStatus
}
const registry = new Map<string, ChannelEntry<any>>()

function buildPgFilter(
  branchId: string | undefined,
  extra?: Record<string, string | number>,
): string | undefined {
  const parts: string[] = []
  if (branchId) parts.push(`branch_id=eq.${branchId}`)
  if (extra) {
    for (const [k, v] of Object.entries(extra)) {
      parts.push(`${k}=eq.${v}`)
    }
  }
  return parts.length ? parts.join(',') : undefined
}

/**
 * Realtime subscriptions helper.
 *
 * `watchTable` deduplicates channels by name so multiple components subscribing
 * to the same `(table, event, filter)` triple share one websocket. Each call
 * bumps the entry's reference count and ADDS the callback to the listener
 * set; the underlying channel is torn down only when the LAST subscriber
 * unmounts. This avoids two bugs we previously had:
 *   1. Silent-disconnect: unmounting one component closed the channel for
 *      everyone else.
 *   2. Lost-callback: a second subscriber's onChange was silently dropped
 *      because the channel was reused without re-wiring.
 */
export function useRealtime() {
  const { branchId } = useAuth()
  const status = ref<RealtimeStatus>('disconnected')
  const activeCleanups = new Set<() => void>()

  function watchTable<T = Record<string, unknown>>(
    table: string,
    event: RealtimeEvent,
    onChange: (payload: ChangePayload<T>) => void,
    filter?: Record<string, string | number>,
  ): () => void {
    const channelName = `watch:${table}:${event}:${JSON.stringify(filter ?? {})}`
    let entry = registry.get(channelName) as ChannelEntry<T> | undefined

    if (!entry) {
      const listeners = new Set<Listener<T>>()
      const ch = supabase
        .channel(channelName)
        .on(
          // `postgres_changes` filter typings don't accept our dynamic filter object.
          'postgres_changes' as never,
          {
            event,
            schema: 'public',
            table,
            filter: buildPgFilter(branchId.value, filter),
          },
          (payload: ChangePayload<T>) => {
            // Fan out to every subscriber. Iterating over a Set is safe
            // while callbacks may themselves remove listeners — a
            // callback that triggers `cleanup()` only removes itself
            // from the local copy thanks to the spread.
            for (const cb of Array.from(listeners)) {
              try { cb(payload) } catch (e) {
                console.warn('[useRealtime] listener threw:', e)
              }
            }
          },
        )
        .subscribe((s) => {
          // The first subscriber owns the channel-level status mirror so
          // late joiners can pick it up.
          const next: RealtimeStatus =
            s === 'SUBSCRIBED' ? 'connected'
              : s === 'CLOSED' ? 'disconnected'
              : s === 'CHANNEL_ERROR' ? 'error'
              : 'connecting'
          entry!.status = next
        })
      entry = { ch, listeners, ref: 0, status: 'connecting' }
      registry.set(channelName, entry)
    }

    entry.listeners.add(onChange)
    entry.ref += 1
    // Adopt the latest channel status so this composable's `status` ref
    // doesn't sit at `disconnected` while the channel is actually live.
    status.value = entry.status

    function cleanup() {
      const e = registry.get(channelName)
      if (!e) return
      e.listeners.delete(onChange)
      e.ref = Math.max(0, e.ref - 1)
      activeCleanups.delete(cleanup)
      if (e.ref <= 0) {
        supabase.removeChannel(e.ch)
        registry.delete(channelName)
      }
    }
    activeCleanups.add(cleanup)
    return cleanup
  }

  function cleanupAll() {
    for (const fn of Array.from(activeCleanups)) fn()
    activeCleanups.clear()
  }

  onUnmounted(cleanupAll)

  return { watchTable, status, cleanupAll }
}

import { computed, onBeforeUnmount, watch, type Ref } from 'vue'
import Swal from 'sweetalert2'
import { useI18nStore } from '@/stores/i18n'

/**
 * Composable for modals / drawers that hold editable form state.
 *
 * Usage:
 *
 *   const { isDirty, confirmIfDirty } = useUnsavedGuard(form, baseline)
 *
 *   <button @click="close()">Cancel</button>
 *
 *   async function close() {
 *     if (await confirmIfDirty()) {
 *       isOpen.value = false
 *     }
 *   }
 *
 * `form` and `baseline` are arbitrary reactive objects. We do a shallow JSON
 * compare — fine for primitives, refs and arrays of primitives, which is what
 * most modal forms hold. If a view needs deep equality for nested objects,
 * pass a `baseline()` function that returns a deep-cloned snapshot.
 *
 * ## Browser back button / tab close
 *
 * The guard also installs (and tears down on scope unmount) two global
 * listeners so the user does not silently lose typed changes via:
 *
 *   1. `beforeunload` — tab close, refresh, hard navigate away. The browser
 *      shows its own native confirmation with copy "Changes you made may not
 *      be saved" (we don't get to choose the wording). When the form is
 *      clean, the listener is a no-op and the browser prompts normally.
 *   2. `popstate` — back/forward button navigation. We push a sentinel state
 *      into `history.state` whenever the form becomes dirty; navigating
 *      away pops it back and triggers our Swal confirm. On "Keep editing"
 *      we re-push the sentinel so the user can keep typing. On "Discard"
 *      we navigate on to the requested route.
 *
 * Both listeners are removed automatically when the calling component
 * unmounts (`onBeforeUnmount`), so they never leak across routes.
 */
export function useUnsavedGuard<T>(
  form: Ref<T>,
  baseline: Ref<T> | (() => T),
) {
  const { t } = useI18nStore()

  const baselineValue = computed<T>(() =>
    typeof baseline === 'function' ? (baseline as () => T)() : baseline.value,
  )

  const isDirty = computed(
    () => JSON.stringify(form.value) !== JSON.stringify(baselineValue.value),
  )

  async function confirmIfDirty(): Promise<boolean> {
    if (!isDirty.value) return true
    const r = await Swal.fire({
      icon: 'warning',
      title: t('common.unsaved_changes_title'),
      text: t('common.unsaved_changes_text'),
      showCancelButton: true,
      confirmButtonText: t('common.discard'),
      cancelButtonText: t('common.keep_editing'),
      reverseButtons: true,
    })
    return r.isConfirmed
  }

  // ---------------------------------------------------------------------------
  // Browser back / tab-close protection
  // ---------------------------------------------------------------------------

  // 1. beforeunload — tab close / refresh / external navigation.
  //    The browser shows its own native dialog; we just need to return a
  //    non-empty `event.returnValue` while the form is dirty.
  function onBeforeUnload(event: BeforeUnloadEvent) {
    if (isDirty.value) {
      event.preventDefault()
      // Legacy browsers (and current Firefox) require setting returnValue.
      event.returnValue = t('common.unsaved_changes_text')
      return event.returnValue
    }
    return undefined
  }

  // 2. popstate — back/forward button. We push a sentinel history entry
  //    whenever the form becomes dirty, so a back-button pop lands on our
  //    sentinel instead of leaving the page silently. The handler asks
  //    whether to discard, then either re-pushes (keep editing) or
  //    history.back() (discard and continue navigating).
  const SENTINEL_KEY = '__useUnsavedGuard_sentinel'
  let sentinelInstalled = false

  function pushSentinel() {
    if (typeof window === 'undefined') return
    if (sentinelInstalled) return
    window.history.pushState({ [SENTINEL_KEY]: true }, '', window.location.href)
    sentinelInstalled = true
  }

  function removeSentinel() {
    if (typeof window === 'undefined') return
    if (!sentinelInstalled) return
    // Step off our sentinel without firing another popstate.
    if (window.history.state && (window.history.state as any)[SENTINEL_KEY]) {
      window.history.go(-1)
    }
    sentinelInstalled = false
  }

  async function onPopState(_event: PopStateEvent) {
    if (!isDirty.value) {
      // Form became clean while on the sentinel — quietly consume it.
      sentinelInstalled = false
      return
    }
    // User is trying to leave. Stop and ask.
    const discard = await confirmIfDirty()
    if (discard) {
      // Allow navigation: drop the sentinel flag and re-fire the back.
      sentinelInstalled = false
      window.removeEventListener('popstate', onPopState)
      window.history.back()
      // Re-install listener after the navigation flush; the caller is gone
      // by then anyway (component unmount).
      return
    }
    // Keep editing — re-push the sentinel so subsequent back-presses still
    // land on us.
    pushSentinel()
  }

  // Install / tear down depending on dirty state.
  if (typeof window !== 'undefined') {
    watch(
      isDirty,
      (dirty) => {
        if (dirty) {
          pushSentinel()
          window.addEventListener('beforeunload', onBeforeUnload)
          window.addEventListener('popstate', onPopState)
        } else {
          // Became clean — quietly remove the sentinel so the back button
          // behaves normally again.
          removeSentinel()
          window.removeEventListener('beforeunload', onBeforeUnload)
          window.removeEventListener('popstate', onPopState)
        }
      },
      { immediate: true },
    )

    onBeforeUnmount(() => {
      window.removeEventListener('beforeunload', onBeforeUnload)
      window.removeEventListener('popstate', onPopState)
      removeSentinel()
    })
  }

  return { isDirty, confirmIfDirty }
}

